// Extract highlight clips from WayinVideo Find Moments
const clips = $('4. WayinVideo — Get Moments Results').item.json.data?.clips || [];

if (clips.length === 0) {
  throw new Error('No financial moments found in this recording. Try a broader search query or verify the recording URL is accessible.');
}

// Get form data
const companyName = $('1. Form — Earnings Call + Details').item.json['Company Name'];
const tickerSymbol = $('1. Form — Earnings Call + Details').item.json['Ticker Symbol'];
const quarter = $('1. Form — Earnings Call + Details').item.json['Quarter / Period'];
const callDate = $('1. Form — Earnings Call + Details').item.json['Call Date'];
const financialTopics = $('1. Form — Earnings Call + Details').item.json['Financial Topics to Extract'];
const investmentThesis = $('1. Form — Earnings Call + Details').item.json['Your Investment Thesis'] || 'General analysis';
const recordingUrl = $('1. Form — Earnings Call + Details').item.json['Earnings Call Recording URL'];

// Split into individual items — one per highlight moment
return clips.map((clip, index) => ({
  json: {
    clipIndex: index + 1,
    totalClips: clips.length,
    clipTitle: clip.title || `Financial Highlight ${index + 1}`,
    clipDescription: clip.desc || '',
    clipScore: clip.score || 0,
    clipTags: Array.isArray(clip.tags) ? clip.tags.join(', ') : '',
    beginMs: clip.begin_ms || 0,
    endMs: clip.end_ms || 0,
    timestampStart: `${Math.floor((clip.begin_ms || 0) / 60000)}:${String(Math.floor(((clip.begin_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    timestampEnd: `${Math.floor((clip.end_ms || 0) / 60000)}:${String(Math.floor(((clip.end_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    companyName,
    tickerSymbol,
    quarter,
    callDate,
    financialTopics,
    investmentThesis,
    recordingUrl
  }
}));

// Parse AI investor analysis output
const output = $input.first().json.output || '';

// Extract each section
const topicCategoryMatch = output.match(/TOPIC_CATEGORY:\s*([\s\S]*?)(?=\nINVESTOR_SUMMARY:|$)/);
const summaryMatch = output.match(/INVESTOR_SUMMARY:\s*([\s\S]*?)(?=\nKEY_METRICS_MENTIONED:|$)/);
const metricsMatch = output.match(/KEY_METRICS_MENTIONED:\s*([\s\S]*?)(?=\nWHY_IT_MATTERS:|$)/);
const whyMattersMatch = output.match(/WHY_IT_MATTERS:\s*([\s\S]*?)(?=\nSENTIMENT:|$)/);
const sentimentMatch = output.match(/SENTIMENT:\s*([\s\S]*?)(?=\nSENTIMENT_REASONING:|$)/);
const sentimentReasoningMatch = output.match(/SENTIMENT_REASONING:\s*([\s\S]*?)(?=\nFLAGS_FOR_ATTENTION:|$)/);
const flagsMatch = output.match(/FLAGS_FOR_ATTENTION:\s*([\s\S]*?)(?=\nNOTION_PAGE_CONTENT:|$)/);
const notionContentMatch = output.match(/NOTION_PAGE_CONTENT:\s*([\s\S]*)$/);

const topicCategory = topicCategoryMatch ? topicCategoryMatch[1].trim() : 'Other';
const investorSummary = summaryMatch ? summaryMatch[1].trim() : '';
const keyMetrics = metricsMatch ? metricsMatch[1].trim() : 'No specific metrics mentioned';
const whyItMatters = whyMattersMatch ? whyMattersMatch[1].trim() : '';
const sentiment = sentimentMatch ? sentimentMatch[1].trim() : 'Neutral';
const sentimentReasoning = sentimentReasoningMatch ? sentimentReasoningMatch[1].trim() : '';
const flagsForAttention = flagsMatch ? flagsMatch[1].trim() : 'None identified';
const notionContent = notionContentMatch ? notionContentMatch[1].trim() : investorSummary;

// Get clip data from previous step
const clipData = $('7. Code — Extract Highlight Clips').item.json;

// Build Notion page title
const pageTitle = `${clipData.companyName} ${clipData.tickerSymbol} — ${clipData.quarter} — ${topicCategory} — Highlight ${clipData.clipIndex}`;

return [{
  json: {
    pageTitle,
    topicCategory,
    investorSummary,
    keyMetrics,
    whyItMatters,
    sentiment,
    sentimentReasoning,
    flagsForAttention,
    notionContent,
    companyName: clipData.companyName,
    tickerSymbol: clipData.tickerSymbol,
    quarter: clipData.quarter,
    callDate: clipData.callDate,
    timestamp: `${clipData.timestampStart} — ${clipData.timestampEnd}`,
    relevanceScore: clipData.clipScore,
    clipTitle: clipData.clipTitle,
    recordingUrl: clipData.recordingUrl,
    clipIndex: clipData.clipIndex
  }
}];
